# solution.py
"""Team collaboration platform.

A standard-library-only, thread-safe in-memory platform that manages users,
projects, tasks, messaging, performance metrics, and reporting. The public
facade is :class:`TeamCollaborationManager`, which exposes a set of
sub-managers that all share a single lock and a single global id counter.
"""

import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the platform."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not allowed to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Roles a user can hold on the platform."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Identifiers for the kinds of reports produced."""

    TEAM_PERFORMANCE = "team_performance"


# ---------------------------------------------------------------------------
# Data model objects
# ---------------------------------------------------------------------------
class Attachment:
    """A file attached to a message."""

    def __init__(self, filename, size, uploaded_by, uploaded_at):
        """Store attachment metadata."""
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at


class User:
    """A registered platform user."""

    def __init__(self, id, username, email, role, created_at):
        """Initialise a user record."""
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at


class Project:
    """A project owned by a user."""

    def __init__(self, id, name, start_date, end_date, owner_id,
                 description=None, created_at=None):
        """Initialise a project record."""
        self.id = id
        self.name = name
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.description = description
        self.created_at = created_at


class Task:
    """A unit of work within a project."""

    def __init__(self, id, project_id, title, status=TaskStatus.NOT_STARTED,
                 assignee_id=None, deadline=None, started_at=None,
                 completed_at=None):
        """Initialise a task record."""
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at


class Message:
    """A message posted to a project or task."""

    def __init__(self, id, author_id, body, project_id=None, task_id=None,
                 parent_id=None, attachments=None, edited_at=None,
                 created_at=None):
        """Initialise a message record."""
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments if attachments is not None else []
        self.edited_at = edited_at
        self.created_at = created_at


class Rating:
    """A peer rating with an optional textual feedback."""

    def __init__(self, score, feedback=None):
        """Initialise a rating record."""
        self.score = score
        self.feedback = feedback


# ---------------------------------------------------------------------------
# Shared context
# ---------------------------------------------------------------------------
class _Context:
    """Shared state used by every sub-manager.

    Holds the single lock, the global id counter, the injected clock, and the
    in-memory data stores so that all sub-managers operate on identical state.
    """

    def __init__(self, now):
        """Create the shared context with the given clock callable."""
        self.lock = threading.RLock()
        self.now = now
        self._next_id = 1

        self.users = {}
        self.projects = {}
        self.tasks = {}
        self.messages = {}

        self.tasks_by_project = {}
        self.tasks_by_assignee = {}
        self.messages_by_project = {}
        self.messages_by_task = {}
        self.ratings_by_ratee = {}

    def next_id(self):
        """Return the next globally unique id under the shared lock."""
        with self.lock:
            value = self._next_id
            self._next_id += 1
            return value


# ---------------------------------------------------------------------------
# Sub-managers
# ---------------------------------------------------------------------------
class _SubManager:
    """Base sub-manager exposing the shared lock and context."""

    def __init__(self, ctx):
        """Bind the sub-manager to the shared context."""
        self._ctx = ctx
        self._lock = ctx.lock

    @property
    def _now(self):
        return self._ctx.now


def _validate_email(email):
    if not email or not str(email).strip():
        raise ValidationError("email must not be empty")
    if "@" not in email:
        raise ValidationError("email must contain '@'")


class _UserManager(_SubManager):
    """Manages user lifecycle operations."""

    def register_user(self, username, email, role=UserRole.MEMBER):
        """Register a new user and return it."""
        with self._lock:
            if not username or not str(username).strip():
                raise ValidationError("username must not be empty")
            _validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            for user in self._ctx.users.values():
                if user.username == username:
                    raise DuplicateError("username already taken")
            for user in self._ctx.users.values():
                if user.email == email:
                    raise DuplicateError("email already taken")
            uid = self._ctx.next_id()
            user = User(uid, username, email, role, self._now())
            self._ctx.users[uid] = user
            return copy.deepcopy(user)

    def get_user(self, user_id):
        """Return a copy of the user with the given id."""
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self):
        """Return all users in ascending id order."""
        with self._lock:
            return [copy.deepcopy(self._ctx.users[uid])
                    for uid in sorted(self._ctx.users)]

    def update_user(self, user_id, username=None, email=None, role=None):
        """Update mutable fields of a user and return the updated copy."""
        with self._lock:
            user = self._require_user(user_id)
            if username is not None:
                if not username.strip():
                    raise ValidationError("username must not be empty")
            if email is not None:
                _validate_email(email)
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username is not None:
                for other in self._ctx.users.values():
                    if other.id != user_id and other.username == username:
                        raise DuplicateError("username already taken")
            if email is not None:
                for other in self._ctx.users.values():
                    if other.id != user_id and other.email == email:
                        raise DuplicateError("email already taken")
            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id):
        """Delete a user, rejecting if they own projects or open tasks."""
        with self._lock:
            self._require_user(user_id)
            for project in self._ctx.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for task_id in self._ctx.tasks_by_assignee.get(user_id, []):
                task = self._ctx.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open assigned task")
            self._ctx.tasks_by_assignee.pop(user_id, None)
            del self._ctx.users[user_id]
            return None

    def _require_user(self, user_id):
        user = self._ctx.users.get(user_id)
        if user is None:
            raise NotFoundError("user not found")
        return user


class _ProjectManager(_SubManager):
    """Manages project lifecycle operations."""

    def create_project(self, name, start_date, end_date, owner_id,
                       description=None):
        """Create a new project and return it."""
        with self._lock:
            if not name or not str(name).strip():
                raise ValidationError("name must not be empty")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            if owner_id not in self._ctx.users:
                raise NotFoundError("owner not found")
            pid = self._ctx.next_id()
            project = Project(pid, name, start_date, end_date, owner_id,
                              description, self._now())
            self._ctx.projects[pid] = project
            self._ctx.tasks_by_project.setdefault(pid, [])
            self._ctx.messages_by_project.setdefault(pid, [])
            return copy.deepcopy(project)

    def get_project(self, project_id):
        """Return a copy of the project with the given id."""
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self):
        """Return all projects in ascending id order."""
        with self._lock:
            return [copy.deepcopy(self._ctx.projects[pid])
                    for pid in sorted(self._ctx.projects)]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        """Update mutable fields of a project and return the updated copy."""
        with self._lock:
            project = self._require_project(project_id)
            if name is not None and not str(name).strip():
                raise ValidationError("name must not be empty")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")
            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, project_id):
        """Delete a project, cascading to its tasks and messages."""
        with self._lock:
            self._require_project(project_id)
            for task_id in list(self._ctx.tasks_by_project.get(project_id, [])):
                task = self._ctx.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    assignee_tasks = self._ctx.tasks_by_assignee.get(
                        task.assignee_id)
                    if assignee_tasks is not None and task_id in assignee_tasks:
                        assignee_tasks.remove(task_id)
                self._ctx.messages_by_task.pop(task_id, None)
            self._ctx.tasks_by_project.pop(project_id, None)
            for msg_id in list(self._ctx.messages_by_project.get(project_id, [])):
                self._ctx.messages.pop(msg_id, None)
            self._ctx.messages_by_project.pop(project_id, None)
            self._ctx.messages = {
                mid: m for mid, m in self._ctx.messages.items()
                if not (m.task_id is not None
                        and m.task_id not in self._ctx.tasks)
            }
            del self._ctx.projects[project_id]
            return None

    def _require_project(self, project_id):
        project = self._ctx.projects.get(project_id)
        if project is None:
            raise NotFoundError("project not found")
        return project


class _TaskManager(_SubManager):
    """Manages task lifecycle and assignment operations."""

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        """Create a new task and return it."""
        with self._lock:
            if project_id not in self._ctx.projects:
                raise NotFoundError("project not found")
            if not title or not str(title).strip():
                raise ValidationError("title must not be empty")
            if assignee_id is not None and assignee_id not in self._ctx.users:
                raise NotFoundError("assignee not found")
            if deadline is not None and deadline < self._now():
                raise ValidationError("deadline must not be in the past")
            tid = self._ctx.next_id()
            task = Task(tid, project_id, title, TaskStatus.NOT_STARTED,
                        assignee_id, deadline)
            self._ctx.tasks[tid] = task
            self._ctx.tasks_by_project.setdefault(project_id, []).append(tid)
            if assignee_id is not None:
                self._ctx.tasks_by_assignee.setdefault(
                    assignee_id, []).append(tid)
            return copy.deepcopy(task)

    def get_task(self, task_id):
        """Return a copy of the task with the given id."""
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        """Return tasks for a project in insertion order."""
        with self._lock:
            if project_id not in self._ctx.projects:
                raise NotFoundError("project not found")
            return [copy.deepcopy(self._ctx.tasks[tid])
                    for tid in self._ctx.tasks_by_project.get(project_id, [])]

    def list_tasks_by_assignee(self, user_id):
        """Return tasks assigned to a user in insertion order."""
        with self._lock:
            if user_id not in self._ctx.users:
                raise NotFoundError("user not found")
            return [copy.deepcopy(self._ctx.tasks[tid])
                    for tid in self._ctx.tasks_by_assignee.get(user_id, [])]

    def assign_task(self, task_id, user_id):
        """Assign a task to a user and update the assignee index."""
        with self._lock:
            task = self._require_task(task_id)
            if user_id not in self._ctx.users:
                raise NotFoundError("user not found")
            self._set_assignee(task, user_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_user_id):
        """Reassign a task to a new user."""
        with self._lock:
            task = self._require_task(task_id)
            if new_user_id not in self._ctx.users:
                raise NotFoundError("user not found")
            self._set_assignee(task, new_user_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id):
        """Remove the assignee from a task."""
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        """Set or clear a task's deadline."""
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None and deadline < self._now():
                raise ValidationError("deadline must not be in the past")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        """Update a task's status and maintain timestamps."""
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    def _set_assignee(self, task, user_id):
        old = task.assignee_id
        if old is not None and old != user_id:
            old_list = self._ctx.tasks_by_assignee.get(old)
            if old_list is not None and task.id in old_list:
                old_list.remove(task.id)
        if user_id is not None and user_id != old:
            self._ctx.tasks_by_assignee.setdefault(
                user_id, []).append(task.id)
        task.assignee_id = user_id

    def _require_task(self, task_id):
        task = self._ctx.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task not found")
        return task


class _MessageManager(_SubManager):
    """Manages message posting, editing, and retrieval."""

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        """Post a message to a project or task and return it."""
        with self._lock:
            if author_id not in self._ctx.users:
                raise NotFoundError("author not found")
            if project_id is None and task_id is None:
                raise ValidationError("a project_id or task_id is required")
            if project_id is not None and task_id is not None:
                raise ValidationError("only one target is allowed")
            if project_id is not None and project_id not in self._ctx.projects:
                raise NotFoundError("project not found")
            if task_id is not None and task_id not in self._ctx.tasks:
                raise NotFoundError("task not found")
            if parent_id is not None and parent_id not in self._ctx.messages:
                raise NotFoundError("parent message not found")
            built = self._build_attachments(attachments, author_id)
            has_body = bool(body) and bool(str(body).strip())
            if not has_body and not built:
                raise ValidationError("message requires a body or attachment")
            mid = self._ctx.next_id()
            message = Message(mid, author_id, body, project_id, task_id,
                              parent_id, built, None, self._now())
            self._ctx.messages[mid] = message
            if project_id is not None:
                self._ctx.messages_by_project.setdefault(
                    project_id, []).append(mid)
            if task_id is not None:
                self._ctx.messages_by_task.setdefault(
                    task_id, []).append(mid)
            return copy.deepcopy(message)

    def edit_message(self, message_id, editor_id, new_body):
        """Edit a message body; only the author may edit."""
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit")
            if not new_body or not str(new_body).strip():
                raise ValidationError("body must not be empty")
            message.body = new_body
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(self, message_id, editor_id, filename, data):
        """Append an attachment to a message; only the author may do so."""
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may attach")
            if not filename or not str(filename).strip():
                raise ValidationError("filename must not be empty")
            message.attachments.append(
                Attachment(filename, len(data), editor_id, self._now()))
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id):
        """Return messages for a project in insertion order."""
        with self._lock:
            if project_id not in self._ctx.projects:
                raise NotFoundError("project not found")
            return [copy.deepcopy(self._ctx.messages[mid])
                    for mid in self._ctx.messages_by_project.get(project_id, [])]

    def list_messages_by_task(self, task_id):
        """Return messages for a task in insertion order."""
        with self._lock:
            if task_id not in self._ctx.tasks:
                raise NotFoundError("task not found")
            return [copy.deepcopy(self._ctx.messages[mid])
                    for mid in self._ctx.messages_by_task.get(task_id, [])]

    def delete_message(self, message_id, editor_id):
        """Delete a message; only the author may delete."""
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may delete")
            if message.project_id is not None:
                lst = self._ctx.messages_by_project.get(message.project_id)
                if lst is not None and message_id in lst:
                    lst.remove(message_id)
            if message.task_id is not None:
                lst = self._ctx.messages_by_task.get(message.task_id)
                if lst is not None and message_id in lst:
                    lst.remove(message_id)
            del self._ctx.messages[message_id]
            return None

    def _build_attachments(self, attachments, uploaded_by):
        result = []
        if attachments:
            now = self._now()
            for filename, data in attachments:
                result.append(
                    Attachment(filename, len(data), uploaded_by, now))
        return result

    def _require_message(self, message_id):
        message = self._ctx.messages.get(message_id)
        if message is None:
            raise NotFoundError("message not found")
        return message


class _PerformanceManager(_SubManager):
    """Computes performance metrics and manages ratings."""

    def get_completion_rate(self, user_id):
        """Return the fraction of assigned tasks that are completed."""
        with self._lock:
            tasks = self._assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        """Return mean completion time in seconds, or None if no completions."""
        with self._lock:
            tasks = self._assigned_tasks(user_id)
            durations = [
                (t.completed_at - t.started_at).total_seconds()
                for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None and t.completed_at is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback=None,
                      task_id=None):
        """Record a peer rating and return it."""
        with self._lock:
            if not isinstance(score, int) or score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if rater_id not in self._ctx.users:
                raise NotFoundError("rater not found")
            if ratee_id not in self._ctx.users:
                raise NotFoundError("ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if task_id is not None and task_id not in self._ctx.tasks:
                raise NotFoundError("task not found")
            rating = Rating(score, feedback)
            self._ctx.ratings_by_ratee.setdefault(ratee_id, []).append(rating)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id):
        """Return a summary of all ratings received by a user."""
        with self._lock:
            if user_id not in self._ctx.users:
                raise NotFoundError("user not found")
            ratings = self._ctx.ratings_by_ratee.get(user_id, [])
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count
                       if count else 0.0)
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        """Return an aggregated performance dashboard for a user."""
        with self._lock:
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total else 0.0
            avg_time = self.get_average_completion_time(user_id)
            ratings = self._ctx.ratings_by_ratee.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (sum(r.score for r in ratings) / rating_count
                              if rating_count else 0.0)
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    def _assigned_tasks(self, user_id):
        if user_id not in self._ctx.users:
            raise NotFoundError("user not found")
        return [self._ctx.tasks[tid]
                for tid in self._ctx.tasks_by_assignee.get(user_id, [])
                if tid in self._ctx.tasks]


class _ReportManager(_SubManager):
    """Produces and exports reports."""

    def project_progress_report(self, project_id):
        """Return a progress report for a project."""
        with self._lock:
            if project_id not in self._ctx.projects:
                raise NotFoundError("project not found")
            now = self._now()
            tasks = [self._ctx.tasks[tid]
                     for tid in self._ctx.tasks_by_project.get(project_id, [])]
            total = len(tasks)
            status_counts = {
                TaskStatus.COMPLETED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.NOT_STARTED.value: 0,
            }
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (task.deadline is not None and task.deadline < now
                        and task.status != TaskStatus.COMPLETED):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0})
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0
            return {
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        """Return a performance report across users with tasks."""
        with self._lock:
            if project_id is not None and project_id not in self._ctx.projects:
                raise NotFoundError("project not found")
            if project_id is None:
                user_ids = [uid for uid, tids
                            in self._ctx.tasks_by_assignee.items()
                            if any(t in self._ctx.tasks for t in tids)]
            else:
                project_tasks = set(
                    self._ctx.tasks_by_project.get(project_id, []))
                user_ids = []
                for uid, tids in self._ctx.tasks_by_assignee.items():
                    if any(tid in project_tasks for tid in tids):
                        user_ids.append(uid)
            rows = []
            for uid in sorted(set(user_ids)):
                if uid not in self._ctx.users:
                    continue
                rows.append(self._performance_row(uid, project_id))
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        """Return a per-task performance report for one user."""
        with self._lock:
            if user_id not in self._ctx.users:
                raise NotFoundError("user not found")
            tids = self._ctx.tasks_by_assignee.get(user_id, [])
            tasks = [self._ctx.tasks[tid] for tid in tids
                     if tid in self._ctx.tasks]
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED)
            task_rows = []
            for task in tasks:
                task_rows.append({
                    "task_id": task.id,
                    "title": task.title,
                    "status": task.status.value,
                })
            return {
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": completed,
                "tasks": task_rows,
            }

    def export_report(self, report, format):
        """Export a report dictionary to CSV text or PDF bytes."""
        with self._lock:
            if not isinstance(format, ReportFormat):
                raise ValidationError("format must be a ReportFormat")
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if format == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    def _performance_row(self, user_id, project_id):
        tids = self._ctx.tasks_by_assignee.get(user_id, [])
        tasks = [self._ctx.tasks[tid] for tid in tids
                 if tid in self._ctx.tasks]
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        completion_rate = completed / total if total else 0.0
        return {
            "user_id": user_id,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completion_rate,
        }

    def _to_csv(self, report):
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list) and rows and isinstance(rows[0], dict):
            headers = list(rows[0].keys())
            writer.writerow(headers)
            for row in rows:
                writer.writerow([row.get(h) for h in headers])
        else:
            scalar_items = [(k, v) for k, v in report.items()
                            if not isinstance(v, (dict, list))]
            writer.writerow([k for k, _ in scalar_items])
            writer.writerow([v for _, v in scalar_items])
        return buffer.getvalue()

    def _to_pdf(self, report):
        lines = []
        for key, value in report.items():
            lines.append("{0}: {1}".format(key, value))
        text = "\n".join(lines)
        ascii_text = text.encode("ascii", "replace").decode("ascii")
        body = "%PDF-1.4\n" + ascii_text + "\n%%EOF\n"
        return body.encode("ascii")


